    98→func TestSourcesHandlerList(t *testing.T) {
    99→	store := &mockSourcesStore{
   100→		sources: []models.Source{
   101→			{ID: "s1", ProjectID: "p1", Provider: "docker_hub", Repository: "library/nginx", Enabled: true, CreatedAt: time.Now(), UpdatedAt: time.Now()},
   102→			{ID: "s2", ProjectID: "p1", Provider: "github", Repository: "golang/go", Enabled: true, CreatedAt: time.Now(), UpdatedAt: time.Now()},
   103→		},
   104→	}
   105→	mux := setupSourcesMux(store)
   106→
   107→	w := httptest.NewRecorder()
   108→	r := httptest.NewRequest(http.MethodGet, "/projects/p1/sources", nil)
   109→	mux.ServeHTTP(w, r)
   110→
   111→	if w.Code != http.StatusOK {
   112→		t.Fatalf("expected status 200, got %d", w.Code)
   113→	}
   114→
   115→	var got struct {
   116→		Data []models.Source `json:"data"`
   117→		Meta struct {
   118→			Page    int `json:"page"`
   119→			PerPage int `json:"per_page"`
   120→			Total   int `json:"total"`
   121→		} `json:"meta"`
   122→	}
   123→	if err := json.NewDecoder(w.Body).Decode(&got); err != nil {
   124→		t.Fatalf("decode: %v", err)
   125→	}
   126→	if len(got.Data) != 2 {
   127→		t.Fatalf("expected 2 sources, got %d", len(got.Data))
   128→	}
   129→	if got.Meta.Total != 2 {
   130→		t.Fatalf("expected total=2, got %d", got.Meta.Total)
   131→	}
   132→}
