    11→// Orchestrator runs polling ingestion sources on a fixed interval.
    12→type Orchestrator struct {
    13→	service       *Service
    14→	loader        *SourceLoader
    15→	pool          *pgxpool.Pool
    16→	staticSources []IIngestionSource // for testing only
    17→	interval      time.Duration
    18→}
    19→
    20→// NewOrchestrator creates an orchestrator that dynamically loads enabled
    21→// sources from the database on each poll cycle.
    22→func NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
    23→	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
    24→}
    25→
    26→// NewOrchestratorWithSources creates an orchestrator with a static source list.
    27→// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
    28→func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
    29→	return &Orchestrator{service: service, staticSources: sources, interval: interval}
    30→}
    31→
    32→// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
    33→func (o *Orchestrator) Run(ctx context.Context) {
    34→	ticker := time.NewTicker(o.interval)
    35→	defer ticker.Stop()
    36→
    37→	o.pollAll(ctx)
    38→
    39→	for {
    40→		select {
    41→		case <-ctx.Done():
    42→			return
    43→		case <-ticker.C:
    44→			o.pollAll(ctx)
    45→		}
    46→	}
    47→}
    48→
    49→func (o *Orchestrator) pollAll(ctx context.Context) {
    50→	sources := o.staticSources
    51→	if sources == nil {
    52→		scheduled, err := o.loader.LoadEnabledSources(ctx)
    53→		if err != nil {
    54→			slog.Error("load sources failed", "err", err)
    55→			return
    56→		}
    57→		if len(scheduled) == 0 {
    58→			slog.Debug("no enabled sources to poll")
    59→			return
    60→		}
    61→		now := time.Now()
    62→		for _, ss := range scheduled {
    63→			if ss.LastPolledAt != nil {
    64→				interval := time.Duration(ss.PollIntervalSeconds) * time.Second
    65→				if now.Before(ss.LastPolledAt.Add(interval)) {
    66→					continue
    67→				}
    68→			}
    69→			o.pollSource(ctx, ss.Source)
    70→		}
    71→		return
    72→	}
    73→	if len(sources) == 0 {
    74→		slog.Debug("no enabled sources to poll")
    75→		return
    76→	}
    77→	for _, src := range sources {
    78→		o.pollSource(ctx, src)
    79→	}
    80→}
    81→
    82→func (o *Orchestrator) pollSource(ctx context.Context, src IIngestionSource) {
    83→	results, err := src.FetchNewReleases(ctx)
    84→	if err != nil {
    85→		slog.Error("poll failed", "source", src.Name(), "err", err)
    86→		o.updateSourcePollStatus(ctx, src.SourceID(), err)
    87→		return
    88→	}
    89→	o.updateSourcePollStatus(ctx, src.SourceID(), nil)
    90→	if len(results) == 0 {
    91→		return
    92→	}
    93→	if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
    94→		slog.Error("process failed", "source", src.Name(), "err", err)
    95→	}
    96→}
    97→
    98→func (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
    99→	if o.pool == nil {
   100→		return
   101→	}
   102→	var lastError *string
   103→	if pollErr != nil {
   104→		s := pollErr.Error()
   105→		lastError = &s
   106→	}
   107→	_, err := o.pool.Exec(ctx,
   108→		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
   109→		lastError, sourceID)
   110→	if err != nil {
   111→		slog.Error("update source poll status", "source", sourceID, "err", err)
   112→	}
   113→}
