func (NotifyJobArgs) Kind() string { return "notify_release" }

var _ river.JobArgs = NotifyJobArgs{}

// AgentJobArgs is enqueued when an agent run is triggered.
// The worker runs the LLM agent to produce a semantic release.
type AgentJobArgs struct {
	AgentRunID string `json:"agent_run_id"`
	ProjectID  string `json:"project_id"`
	Version    string `json:"version"`
}

func (AgentJobArgs) Kind() string { return "agent_run" }

var _ river.JobArgs = AgentJobArgs{}

// ScanDependenciesJobArgs is enqueued when a user requests a GitHub repo scan.
// The worker fetches dependency files and extracts dependencies via LLM.
type ScanDependenciesJobArgs struct {
	ScanID string `json:"scan_id"`
}

func (ScanDependenciesJobArgs) Kind() string { return "scan_dependencies" }

var _ river.JobArgs = ScanDependenciesJobArgs{}

package ingestion

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// ScheduledSource wraps an IIngestionSource with its scheduling metadata
// so the orchestrator can decide whether the source is due for polling.
type ScheduledSource struct {
	Source              IIngestionSource
	PollIntervalSeconds int
	LastPolledAt         *time.Time
}

// SourceLoader reads source configuration from the database and constructs
// IIngestionSource instances. It bridges the API-managed sources table with
// the polling orchestrator.
type SourceLoader struct {
	pool   *pgxpool.Pool
	client *http.Client
}

func NewSourceLoader(pool *pgxpool.Pool, client *http.Client) *SourceLoader {
	return &SourceLoader{pool: pool, client: client}
}

// LoadEnabledSources queries all enabled sources and constructs the
// appropriate IIngestionSource for each one, along with scheduling metadata.
func (l *SourceLoader) LoadEnabledSources(ctx context.Context) ([]ScheduledSource, error) {
	rows, err := l.pool.Query(ctx,
		`SELECT id, provider, repository, poll_interval_seconds, last_polled_at
		 FROM sources WHERE enabled = true`)
	if err != nil {
		return nil, fmt.Errorf("query enabled sources: %w", err)
	}
	defer rows.Close()

	var sources []ScheduledSource
	for rows.Next() {
		var id string
		var sourceType, repository string
		var pollInterval int
		var lastPolledAt *time.Time
		if err := rows.Scan(&id, &sourceType, &repository, &pollInterval, &lastPolledAt); err != nil {
			return nil, fmt.Errorf("scan source row: %w", err)
		}

		src := l.buildSource(id, sourceType, repository)
		if src == nil {
			slog.Warn("unsupported source type, skipping",
				"id", id, "type", sourceType, "repo", repository)
			continue
		}
		sources = append(sources, ScheduledSource{
			Source:              src,
			PollIntervalSeconds: pollInterval,
			LastPolledAt:         lastPolledAt,
		})
	}
	return sources, rows.Err()
}

// LookupSourceID finds the source ID for a given (provider, repository) pair.
// Returns empty string and false if no matching enabled source exists.
func (l *SourceLoader) LookupSourceID(ctx context.Context, provider, repository string) (string, bool) {
	var id string
	err := l.pool.QueryRow(ctx,
		`SELECT id FROM sources WHERE provider = $1 AND repository = $2 AND enabled = true`,
		provider, repository,
	).Scan(&id)
	if err != nil {
		return "", false
	}
	return id, true
}

func (l *SourceLoader) buildSource(id string, sourceType, repository string) IIngestionSource {
	return BuildSource(l.client, id, sourceType, repository)
}

// BuildSource constructs the appropriate IIngestionSource based on provider type.
func BuildSource(client *http.Client, id string, sourceType, repository string) IIngestionSource {
	switch sourceType {
	case "dockerhub":
		return NewDockerHubSource(client, repository, id)
	case "github":
		return NewGitHubSource(client, repository, id)
	case "ecr-public":
		return NewECRPublicSource(client, repository, id)
	case "gitlab":
		return NewGitLabSource(client, repository, id)
	case "pypi":
		return NewPyPISource(client, repository, id)
	default:
		return nil
	}
}

package main

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"time"

	"github.com/riverqueue/river"
	agentpkg "github.com/sentioxyz/changelogue/internal/agent"
	"github.com/sentioxyz/changelogue/internal/api"
	"github.com/sentioxyz/changelogue/internal/db"
	"github.com/sentioxyz/changelogue/internal/ingestion"
	"github.com/sentioxyz/changelogue/internal/onboard"
	"github.com/sentioxyz/changelogue/internal/queue"
	"github.com/sentioxyz/changelogue/internal/routing"
)

func main() {
	// Configure log level from LOG_LEVEL env (debug, info, warn, error).
	logLevel := new(slog.LevelVar) // defaults to Info
	switch os.Getenv("LOG_LEVEL") {
	case "debug":
		logLevel.Set(slog.LevelDebug)
	case "warn":
		logLevel.Set(slog.LevelWarn)
	case "error":
		logLevel.Set(slog.LevelError)
	}
	slog.SetDefault(slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: logLevel})))

	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt)
	defer stop()

	dbURL := envOr("DATABASE_URL", "postgres://localhost:5432/changelogue?sslmode=disable")
	addr := envOr("LISTEN_ADDR", ":8080")
	noAuth := os.Getenv("NO_AUTH") == "true"

	// Database
	pool, err := db.NewPool(ctx, dbURL)
	if err != nil {
		slog.Error("database connection failed", "err", err)
		os.Exit(1)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool); err != nil {
		slog.Error("migrations failed", "err", err)
		os.Exit(1)
	}

	// API & routing store (created before River so we can register workers)
	// The river client is set to nil initially; TriggerAgentRun (which needs it)
	// won't be called until the server is up and the client is set below.
	pgStore := api.NewPgStore(pool, nil)

	// Register River workers
	workers := river.NewWorkers()
	notifyWorker := routing.NewNotifyWorker(pgStore, os.Getenv("PUBLIC_URL"))
	river.AddWorker(workers, notifyWorker)

	// Agent worker: requires an LLM API key. If unavailable, agent jobs
	// will remain in the queue until the key is configured and the server
	// is restarted.
	llmProvider := envOr("LLM_PROVIDER", "gemini")
	llmModelDefault := "gemini-2.5-flash"
	if llmProvider == "openai" {
		llmModelDefault = "gpt-5.2"
	}
	llmConfig := agentpkg.LLMConfig{
		Provider:      llmProvider,
		Model:         envOr("LLM_MODEL", llmModelDefault),
		GoogleAPIKey:  os.Getenv("GOOGLE_API_KEY"),
		OpenAIAPIKey:  os.Getenv("OPENAI_API_KEY"),
		OpenAIBaseURL: os.Getenv("OPENAI_BASE_URL"),
	}
	agentOrchestrator, err := agentpkg.NewOrchestrator(pgStore, llmConfig, os.Getenv("PUBLIC_URL"))
	if err != nil {
		slog.Warn("agent orchestrator not available — agent jobs will not be processed", "err", err)
	} else {
		agentWorker := agentpkg.NewAgentWorker(agentOrchestrator, pgStore)
		river.AddWorker(workers, agentWorker)
		slog.Info("agent worker registered")
	}

	// Scan worker: requires LLM for dependency extraction
	scanScanner := onboard.NewScanner(http.DefaultClient, "", "")
	var scanExtractor *onboard.DependencyExtractor
	extractorCfg := onboard.ExtractorConfig{
		Provider:      llmConfig.Provider,
		Model:         llmConfig.Model,
		GoogleAPIKey:  llmConfig.GoogleAPIKey,
		OpenAIAPIKey:  llmConfig.OpenAIAPIKey,
		OpenAIBaseURL: llmConfig.OpenAIBaseURL,
	}
	ext, err := onboard.NewDependencyExtractor(ctx, extractorCfg)
	if err != nil {
		slog.Warn("dependency extractor not available", "err", err)
	} else {
		scanExtractor = ext
	}
	scanWorker := onboard.NewScanWorker(pgStore, scanScanner, scanExtractor, pool)
	river.AddWorker(workers, scanWorker)
	slog.Info("scan worker registered")

	riverClient, err := queue.NewRiverClient(pool, workers)
	if err != nil {
		slog.Error("river client failed", "err", err)
		os.Exit(1)
	}

	// Now that the river client exists, set it on the existing pgStore so that
	// all holders (including NotifyWorker) can enqueue agent jobs.
	pgStore.SetRiverClient(riverClient)

	if err := riverClient.Start(ctx); err != nil {
		slog.Error("river start failed", "err", err)
		os.Exit(1)
	}

	// Ingestion layer
	ingestionStore := ingestion.NewPgStore(pool, riverClient)
	svc := ingestion.NewService(ingestionStore)

	loader := ingestion.NewSourceLoader(pool, http.DefaultClient)
	orch := ingestion.NewOrchestrator(svc, loader, pool, 5*time.Minute)

	broadcaster := api.NewBroadcaster()

	mux := http.NewServeMux()

	// Serve frontend static export if available
	if info, err := os.Stat("web/out"); err == nil && info.IsDir() {
		api.RegisterFrontend(mux, "web/out")
		slog.Info("serving frontend from web/out")
	}

	// Register all API v1 routes
	api.RegisterRoutes(mux, api.Dependencies{
		DB:                    pool,
		ProjectsStore:         pgStore,
		ReleasesStore:         pgStore,
		SubscriptionsStore:    pgStore,
		SourcesStore:          pgStore,
		ChannelsStore:         pgStore,
		ContextSourcesStore:   pgStore,
		SemanticReleasesStore: pgStore,
		AgentStore:            pgStore,
		TodosStore:            pgStore,
		OnboardStore:          pgStore,
		PublicURL:             os.Getenv("PUBLIC_URL"),
		KeyStore:              pgStore,
		HealthChecker:         pgStore,
		Broadcaster:           broadcaster,
		NoAuth:                noAuth,
		IngestionService:      svc,
		HTTPClient:            http.DefaultClient,
	})

	srv := &http.Server{Addr: addr, Handler: api.CORS(mux)}

	// Start polling in background
	go orch.Run(ctx)

	// Start PostgreSQL LISTEN/NOTIFY → SSE bridge
	go api.ListenForNotifications(ctx, pool, broadcaster)

	// Start HTTP server
	go func() {
		slog.Info("server starting", "addr", srv.Addr)
		if err := srv.ListenAndServe(); err != http.ErrServerClosed {
			slog.Error("server error", "err", err)
		}
	}()

	<-ctx.Done()
	slog.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	riverClient.Stop(shutdownCtx)
	srv.Shutdown(shutdownCtx)
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

